INSERT INTO public.catalogo_servicos (id, empresa_id, nome, categoria, descricao, prazo_estimado, ativo, created_at, updated_at) VALUES ('ea979d25-2334-4d53-92d8-3dbec6d5af23', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', 'Licença Especial de Ruído', 'licenca', 'Autorização (PSIU em SP, etc.) para casas de show, bares e indústrias operarem emitindo som acima dos limites residenciais.
INSERT INTO public.catalogo_servicos (id, empresa_id, nome, categoria, descricao, prazo_estimado, ativo, created_at, updated_at) VALUES ('10747cdd-dbec-4162-9457-cafe4608c2d5', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', 'Abertura de MEI', 'abertura', 'Processo simplificado para formalizar Microempreendedores Individuais com faturamento anual até R$ 81 mil. Inclui registro automático de CNPJ, IE e IM em muitos casos. Ideal para autônomos e pequenos negócios.
