INSERT INTO public.catalogo_servicos (id, empresa_id, nome, categoria, descricao, prazo_estimado, ativo, created_at, updated_at) VALUES ('e9fe5a8d-59be-49c8-b38b-b61c889a4c59', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', 'Abertura de EI (Empresário Individual)', 'abertura', 'Formalização de pessoa física como empresário único, sem limitação de faturamento como no MEI. Responsabilidade patrimonial ilimitada. Permite enquadramento em Simples Nacional.
