INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('24eadcb5-2c2c-4d48-bdde-cdf7a89b2ed9', 14, 'THAIS CACAU ODONTOLOGIA E HARMONIZACAO FACIAL LTDA', '62.587.839/0001-25', 'THAISCACAU96@GMAIL.COM', '(85) 9684-8557', NULL, 'avulso', '[{"id": "ef3b6e7e-df5d-4f9d-bb80-9f2a6034254f", "ordem": 0, "prazo": "", "secao": "geral", "detalhes": "<p>O peticionamento serve para <strong>evitar retrabalho, destravar o andamento do pedido original e formalizar o cumprimento das pendências exigidas pela administração pública</strong>, mantendo o processo ativo e corretamente instruído. Em termos práticos, ele acelera a regularização porque permite complementar o processo já aberto sem necessidade de iniciar tudo novamente, desde que a petição seja apresentada no formato correto e com os documentos exigidos.<br><br>Informamos que <strong>todos os peticionamentos foram realizados em todos os órgãos há mais de 2 meses</strong>, e o processo segue em fase de acompanhamento e impulsionamento administrativo. Isso demonstra atuação contínua, diligente e técnica para evitar paralisação do pedido e acelerar a regularização.</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Peticionamento - SEI", "honorario": 890, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 890.00, 1, 43.80, 500.18, false, 0.00, 0.00, 15, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p><strong>Complexidade do Serviço</strong></p><p>Trata-se de uma atividade que exige <strong>análise técnica do processo anterior, conferência da documentação, identificação da exigência correta, preparação da petição adequada e anexação organizada dos documentos</strong>, observando o rito eletrônico do órgão competente. Além disso, o procedimento depende de cadastro prévio do usuário externo, validação de acesso e conformidade com o fluxo específico do SEI-RJ, o que torna o trabalho mais sensível e técnico do que um simples protocolo comum.<br><br><strong>Peticionamento eletrônico no SEI-RJ para regularização de alvará já protocolado, com análise do processo anterior, identificação de exigências, organização documental e envio da petição complementar para impulsionamento da análise administrativa.</strong></p>', 'aguardando_pagamento', '0f0b825e742136aff7cfacae15a3904f', NULL, NULL, NULL, '2026-04-15 18:10:17.261819+00', '2026-04-15 18:10:17.261819+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>Este serviço consiste no <strong>peticionamento eletrônico no SEI-RJ</strong> para impulsionar a <strong>regularização de um pedido de alvará já protocolado anteriormente</strong>, com a finalidade de agilizar a análise, cumprir exigências pendentes e dar seguimento formal ao processo já existente. No SEI-RJ, o peticionamento eletrônico permite <strong>inserir documentos em processo já existente</strong>, desde que o usuário esteja previamente cadastrado e autorizado no sistema.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'cliente_direto', '[]', '[]', '[]', 'Contexto e Apresentação', '2026-04-15 18:11:31.771+00', '2026-04-15 18:11:38.432+00', '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-30 18:11:31.771+00', false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('c6ed116b-ead4-48cf-be15-c14aed270e09', 15, 'ZYGOS', '33224561000123', 'rafa_pedroso@hotmail.com', '11974923476', NULL, 'avulso', '[{"id": "e38e3040-e2f3-4f16-9410-ab5ef13510cf", "ordem": 1, "prazo": "", "secao": "opcionais", "detalhes": "<p>O valor é composto por:<br><br>Honorários - R$ 780<br>DARE - 218,99<br>Agilidade no deferimento - R$ 819,90<br>Licenciamento + Inscrição Municpal + Inscrição Estadual - <strong>R$ 600,00 (Cortesia pelo volume processual)</strong><br><br><strong>Total por processo - R$ 2.418,89</strong></p>", "taxa_max": 0, "taxa_min": 0, "cenarioId": "9b140463-481d-4257-84dd-24a88087a326", "descricao": "1 CNPJ — Avulso", "honorario": 2418.89, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "4bd73c7e-dc4e-48ad-a494-b0d0288fdac4", "ordem": 2, "prazo": "", "secao": "opcionais", "detalhes": "<p>O valor é composto por:<br><br>Honorários - <strong>R$ 580</strong><br>DARE - <strong>218,99</strong><br>Agilidade no deferimento - <strong>R$ 719,90</strong><br>Licenciamento + Inscrição Municpal + Inscrição Estadual - <strong>R$ 0,00 (Cortesia pelo volume processual)</strong><br><br><strong>Total por processo - R$ 1.518,89 </strong><br><br><strong>Total 10 processos - R$ 15.188,90</strong></p><p></p>", "taxa_max": 0, "taxa_min": 0, "cenarioId": "61043b4a-4a8e-4d4c-b539-afbce9679ce2", "descricao": "10 CNPJs — Lote com desconto", "honorario": 1518.89, "isOptional": false, "quantidade": 10, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 17607.79, 1, 0.00, 17607.79, false, 0.00, 0.00, 15, '<p><strong>Para Opção A</strong> - Pagamento à vista via PIX ou boleto bancário no momento da solicitação de <strong>R$ 2.418,89</strong><br><br><strong>Para Opção B</strong> - Pagamento à vista via PIX ou boleto bancário no momento da solicitação de <strong>R$ 9.388,90</strong> (taxas e agilidade na Junta Comercial), após o deferimento e obtenção da Inscrição CNPJ, o pagamento à vista via PIX ou boleto bancário de <strong>R$ 5.800,00</strong></p>', NULL, '<p><strong><u>Para Opção A</u></strong><u> - Sem observação.</u><br><br><br><strong><u>Para Opção B </u>- </strong>Caso realize o pagamento integral no início do processo via PIX, garantimos 5% de desconto sobre os honrários. <br><br><strong>Honorários com desconto R$ 5.510,00</strong><br><br><strong>Total - R$ 14.898,90</strong></p>', 'enviado', 'ea69a3cc0cce7f9f4a2a2ad090f5e5a1', '9da9bbf1-6ef7-4f28-8710-35b19b01b163', NULL, NULL, '2026-04-16 18:43:24.359134+00', '2026-04-16 18:43:24.359134+00', NULL, 'Prazo de execução: 4 úteis por lote, após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>Solicitação para uma demanda de abertura de 30 a 50 novos CNPJs em lotes de 10, com agilidade no deferimento junto à Junta </p><p>Comercial e Receita Federal.<br><br>Empresas brasileiras com sócio nacional no QSA, atividade de comércio varejista (eletrônicos/peças), operação via marketplace (Mercado Livre, Shopee). Inscrição Municipal e Estadual inclusa como cortesia pelo volume processual.<br><br>Prazo estimado de 3 a 5 dias por lote.</p>', NULL, '[{"id": "68396c11-1b92-4573-9d72-13f97a323cba", "nome": "", "descricao": "", "itens_ids": [], "desconto_pct": 0}]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'cliente_direto', '[{"id": "41ed1ef1-1bbf-451d-a46f-2471ddf076b8", "condicao": "A Trevo garante agilidade total no deferimento junto à Junta  Comercial. Porém, etapas anteriores ao registro — como a  aprovação de Viabilidade (Prefeitura) e emissão do DBE  (Receita Federal) — dependem de órgãos externos com prazos  próprios. Embora raro, eventuais atrasos nessas etapas podem  impactar o prazo total do lote. A Trevo acompanha e aciona  cada órgão proativamente para minimizar qualquer demora.", "penalidade": "Prazo de análise em órgãos prévios (Viabilidade e DBE)"}]', '[{"id": "eeb07d60-40fd-49e4-a89e-e39a341dc5cd", "nome": "Recepção e análise documental", "ordem": 1, "prazo": "1h útil"}, {"id": "9738ad0a-7b58-4359-98bb-0bda5403f286", "nome": "Viabilidade", "ordem": 2, "prazo": "Transmissão em 1h (deferimento da prefeitura em até 24h)"}, {"id": "947612ff-1abd-4629-9f4f-ed0103cc2284", "nome": "DBE", "ordem": 3, "prazo": "Transmissão em 1h (Deferimento da receita Federal em até 10h)"}, {"id": "f80578c6-2f1c-40f7-9570-a28aad1e8137", "nome": "Junta Comercial", "ordem": 4, "prazo": "Deferimento IMEDIATO"}, {"id": "1a2d5366-7c46-4638-9a15-a88f19d80991", "nome": "Licenciamento + Inscrição Municpal", "ordem": 5, "prazo": "1 a 2 dias"}]', '[{"id": "ae778733-93cd-4482-b401-a2db125ab3f6", "titulo": "Deferimento ágil", "descricao": "mercado leva 10+ dias úteis.  🍀 Trevo tem assessoria direta nas juntas."}, {"id": "d9d1d9a5-dd72-49ae-b241-ae273bdca072", "titulo": "Inscrição Municipal", "descricao": "Inclusa como cortesia"}, {"id": "60287fd1-a358-44ed-81bb-6f2316b39c66", "titulo": "Inscrição Estadual", "descricao": "Inclusa como cortesia"}]', 'Abertura em Lote — 30 a 50 CNPJs', '2026-04-16 21:54:24.921+00', NULL, '[{"id": "9b140463-481d-4257-84dd-24a88087a326", "nome": "Opção A", "ordem": 1, "descricao": "1 CNPJ — Avulso"}, {"id": "61043b4a-4a8e-4d4c-b539-afbce9679ce2", "nome": "Opção B", "ordem": 2, "descricao": "10 CNPJs — Lote com desconto"}]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-05-01 21:54:24.921+00', false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('6b4a64b7-862c-44b7-aea1-08aa66329577', 16, 'STUK MINI MERCADO', 'STUK MINI MERCADO DE CONDOMÍNIOS LTDA', NULL, NULL, NULL, 'avulso', '[{"id": "77628ab7-8f49-40bb-a8a2-d14241130a41", "ordem": 0, "prazo": "", "secao": "geral", "detalhes": "<ol><li><p><strong>Encerramento</strong> da empresa constituída em regime tributário inadequado, com realização de viabilidade, DBE, registro e nova abertura da sociedade em conformidade com o planejamento pretendido, utilizando metodologia Trevo e acompanhamento até o deferimento.</p></li><li><p><strong>Abertura </strong>societária e cadastral completa da empresa, com realização de viabilidade, preenchimento e transmissão do DBE, protocolo de registro e acompanhamento até o deferimento, utilizando metodologia Trevo para dar agilidade e segurança ao processo.<br></p></li></ol><p></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "ENCERRAMENTO DA EMPRESA COM ABERTURA SUBSEQUENTE", "honorario": 2900, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 2900.00, 1, 0.00, 2900.00, false, 0.00, 0.00, 1, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p>Honorários com <strong>taxas oficiais já inclusas</strong>, compreendendo DARE, taxas da Junta Comercial, taxas municipais e demais emolumentos necessários ao protocolo e andamento do processo.</p>', 'rascunho', 'fc60253335f8570d0f4ad233008da485', '9da9bbf1-6ef7-4f28-8710-35b19b01b163', NULL, NULL, '2026-04-20 14:12:30.218711+00', '2026-04-20 14:12:30.218711+00', NULL, 'Prazo de execução: até 2 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>O serviço consiste no <strong>encerramento da sociedade STUK MINI MERCADO DE CONDOMÍNIOS LTDA, CNPJ 66.334.211/0001-79</strong>, aberta em 17/04/2026, diante do enquadramento indevido no Lucro Presumido via MAT, e na <strong>abertura de nova pessoa jurídica com a configuração tributária adequada</strong>, evitando que a empresa permaneça com regime incompatível com o planejamento inicial. A medida é indicada quando a opção feita na constituição não atende ao regime desejado e a solução técnica mais segura é promover a baixa do CNPJ atual e iniciar nova estruturação empresarial.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'contador', '[]', '[{"id": "9654663e-2844-4c06-bc7a-70b98a36249e", "nome": "ENCERRAMENTO COMPLETO", "ordem": 1, "prazo": "1 DIA"}, {"id": "be187d7c-b741-4842-a603-5c4f47ecbfb6", "nome": "ABERTURA COMPLETA", "ordem": 2, "prazo": "1 DIA"}]', '[]', 'Regularização societária e tributária com encerramento da empresa constituída e nova abertura com enquadramento correto no regime pretendido.', NULL, NULL, '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('05a3ffe7-cb2c-4490-aa7d-91f3011baeba', 17, 'UPELEV MANUTENCAO DE ELEVADORES LTDA', '30146036000149', NULL, '+55 11 93288-8488', NULL, 'avulso', '[{"id": "915705ab-96cb-480d-9623-514490367276", "ordem": 0, "prazo": "", "secao": "geral", "detalhes": "<p>Referente ao preenchimento técnico e envio das informações da <strong>UPELEV MANUTENCAO DE ELEVADORES LTDA</strong> no portal Facilita SP</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Assessoria Técnica e Transmissão no Integrador Estadual:", "honorario": 450, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "ff5a2f1c-e0fa-41af-9b43-81511f7ca769", "ordem": 2, "prazo": "", "secao": "geral", "detalhes": "<p>Referente à conferência dos dados fornecidos e formalização das declarações de responsabilidade e enquadramento de risco</p><p></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Análise de Conformidade e Gestão de Declarações: ", "honorario": 250, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "03062b55-0313-4f42-98db-fd131ae028d2", "ordem": 3, "prazo": "", "secao": "geral", "detalhes": "<p>Referente à validação final e emissão do Certificado de Licenciamento Integrado (Protocolo <strong>SPM2630226301</strong>).</p><p></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Emissão e Consolidação do CLI:", "honorario": 100, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 800.00, 1, 0.00, 800.00, false, 0.00, 0.00, 1, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p><strong>Observações Importantes</strong></p><ul><li><p><strong>Documentação:</strong> O serviço consistiu estritamente na <strong>transmissão e integração</strong> dos dados no sistema. Toda a documentação base e informações técnicas foram fornecidas pelo cliente, sendo estas de sua inteira responsabilidade.</p><p></p></li><li><p></p><p><strong>Manutenção da Validade:</strong> Qualquer alteração futura nos dados da empresa, endereço ou atividade econômica implicará na perda da validade deste documento, exigindo nova solicitação.</p><p></p></li><li><p></p><p><strong>Taxas:</strong> Lembramos que as taxas específicas de cada órgão (quando aplicáveis) devem ser mantidas pagas e válidas diretamente com as respectivas instituições para evitar a cassação do licenciamento.</p></li></ul><p></p>', 'convertido', '79da59ebcf75fd7eb00b87d82db61c0f', NULL, '2026-04-22 10:45:16.985+00', NULL, '2026-04-20 14:39:21.876491+00', '2026-04-20 14:39:21.876491+00', NULL, 'Já realizado 🍀', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>Esta proposta refere-se aos serviços de regularização cadastral e licenciamento administrativo realizados para a empresa <strong>UPELEV MANUTENCAO DE ELEVADORES LTDA</strong> , inscrita sob o <strong>CNPJ 30.146.036/0001-49.</strong><br>O objetivo foi assegurar a conformidade legal do estabelecimento perante os órgãos estaduais e municipais, garantindo que a empresa opere com as devidas autorizações vigentes.<br><br>A empresa encontrava-se em processo de atualização de suas licenças. Através da compilação de dados e documentos fornecidos, foi realizada a transmissão e integração dos pareceres dos seguintes órgãos:</p><ul><li><p></p><p><strong>Prefeitura de São Paulo:</strong> Análise de viabilidade municipal.</p><p></p></li><li><p></p><p><strong>Corpo de Bombeiros:</strong> Validação do CLCB (Certificado de Licença do Corpo de Bombeiros) válido até 2028.</p><p></p></li><li><p></p><p><strong>Vigilância Sanitária:</strong> Declaração de dispensa/isenção para as atividades exercidas.</p><p></p></li><li><p></p><p><strong>CETESB:</strong> Obtenção de isenção de licenciamento ambiental para o local informado.</p><p></p></li><li><p></p><p><strong>Secretaria da Agricultura:</strong> Protocolo de baixo risco.</p><p></p></li></ul><p>O processo foi concluído com sucesso, gerando o <strong>Protocolo SPM2630226301</strong> , com validade final do CLI estabelecida para <strong>29/08/2028</strong>.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'cliente_direto', '[]', '[]', '[]', 'Regularização e Emissão do Certificado de Licenciamento Integrado (CLI) via Portal Facilita SP.', '2026-04-22 10:45:06.89+00', '2026-04-22 10:45:11.742+00', '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-22 10:45:16.985+00', NULL, false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('ad50f24d-2144-40d8-80fc-8bd44c30e616', 6, 'CBS CONTABILIDADE', '28975756000175', NULL, '11 916568492', NULL, 'avulso', '[{"id": "e84867b5-44e2-482e-9692-4dc8bc81417b", "ordem": 1, "prazo": "", "secao": "obrigatorios", "detalhes": "Análise da documentação societária e cadastral, revisão e adequação do contrato social, correção e regularização de cláusulas societárias, regularização do capital social, organização e formalização da conferência de bens e ativos à holding, elaboração dos atos societários necessários, atualização e regularização cadastral perante a Receita Federal e demais órgãos competentes, análise do enquadramento tributário e fiscal da holding, adequação da estrutura societária aos objetivos dos sócios ou da família, emissão e conferência da documentação final regularizada.", "taxa_max": 0, "taxa_min": 0, "descricao": "Regularização completa", "honorario": 15000, "isOptional": false, "quantidade": 1, "valor_mercado": 30000, "valor_premium": 38000, "docs_necessarios": "RG dos Sócios, Estado civil, certidão de casamento, Contrato Social Atualizado, Última Alteração Registrada, Definição de Capital Social e Participação dos Sócios. IPTU dos Imóveis, Valor Declarado em Imposto de Renda,Matrícula ou documento comprobatório da propriedade", "honorario_contador": 0, "honorario_minimo_contador": 25000}]', '[]', '[]', 15000.00, 1, 0.00, 15000.00, false, 0.00, 0.00, 15, 'Pagamento à vista via PIX ou boleto bancário.', NULL, 'Ressaltamos que, para a regularização da holding, poderá ser necessária a realização de matrícula/atualização de matrícula dos imóveis perante o Cartório de Registro de Imóveis, cujo custo cartorário e taxas correspondentes correrão por conta do contratante.', 'enviado', 'b9c59a98b245dd1a60001c799c635f8a', '4e6a1278-9366-47df-a0a8-282d6aed9364', NULL, NULL, '2026-04-08 21:18:20.260075+00', '2026-04-08 21:18:20.260075+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', 'No processo de regularização são realizados os seguintes serviços:
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('6706c168-1c67-494a-93be-158da26d306d', 18, 'NOURA MANSOUR - CENTRO AVANÇADO DE FISIOTERAPIA RESPIRATÓRIA LTDA', '42.714.789/0001-92', NULL, NULL, NULL, 'avulso', '[{"id": "ebb20fcf-39ed-437c-b53d-acdd5e65a33e", "ordem": 1, "prazo": "10 a 30 dias úteis", "secao": "geral", "detalhes": "<p>Elaboração, preenchimento, transmissão e acompanhamento do cadastro CNES da clínica, incluindo análise documental, cadastro da estrutura física, vinculação do responsável técnico e dos profissionais de saúde, organização dos dados no sistema SCNES e protocolo junto à Secretaria Municipal de Saúde até a conclusão do registro.</p>", "taxa_max": 350, "taxa_min": 0, "descricao": "Registro e regularização de cadastro CNES", "honorario": 1200, "isOptional": false, "quantidade": 1, "valor_mercado": 1800, "valor_premium": 2500, "docs_necessarios": "CNPJ  Contrato social e alterações  Documentos do responsável técnico  Registro profissional do RT  Relação de profissionais vinculados  Comprovante de endereço do estabelecimento  Dados da estrutura física e dos ambientes  Licenças eventualmente exigidas pelo município  Informações de carga horária e CBO dos profissionais", "honorario_contador": 0, "honorario_minimo_contador": 1500}]', '[]', '[]', 1200.00, 1, 0.00, 1200.00, false, 0.00, 0.00, 15, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p><strong>Licenças prévias necessárias para o CNES:</strong> CNPJ, contrato social, alvará de funcionamento, licença sanitária vigente, documento do responsável técnico e documentação dos profissionais vinculados, podendo haver exigências adicionais conforme o município.</p><p><strong>Validade / manutenção do CNES:</strong> o cadastro deve ser mantido atualizado continuamente, com revisão obrigatória a cada alteração relevante e, no máximo, a cada 6 meses, para evitar desativação.</p>', 'rascunho', '1bca5f147633698f0a42c34e3ce3ff5a', '85f0974d-2c73-415b-b556-60e1e854a280', NULL, NULL, '2026-04-22 20:58:18.001424+00', '2026-04-22 20:58:18.001424+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>A empresa atua na área de fisioterapia e necessita da regularização do seu cadastro junto ao CNES, com o objetivo de estruturar corretamente o estabelecimento de saúde perante a base nacional do SUS, organizar os vínculos profissionais, permitir maior segurança documental e apoiar eventual relacionamento com operadoras, auditorias e sistemas de saúde. O serviço envolve análise documental, preenchimento técnico, geração das informações no SCNES, protocolo junto ao órgão competente e acompanhamento até a liberação do cadastro.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'contador', '[{"id": "c18c1746-cf59-42dc-b7b9-b4cba0fa5e1f", "condicao": "", "penalidade": "Inconsistência entre a atividade declarada e a estrutura física informada."}, {"id": "3f6cbd77-f49e-4fcc-b7cc-ec8e24c71998", "condicao": "", "penalidade": "Pendências documentais que impeçam o protocolo ou atrasem a análise."}, {"id": "e95d60a7-cdfe-4db5-ab6a-74212930db36", "condicao": "", "penalidade": "Divergência entre CNES, CNPJ, contrato social e registro profissional."}, {"id": "4a4b580a-1441-48e8-87fa-7c5a942644dc", "condicao": "", "penalidade": "Retrabalho por preenchimento incorreto de carga horária, CBO ou vínculos profissionais."}, {"id": "6c42b07a-bfc6-408b-a34a-5e71df585245", "condicao": "", "penalidade": "Necessidade de retificação caso a empresa não esteja com as informações atualizadas."}]', '[{"id": "a6d9abef-dcb6-4e01-9039-9abf5fc2d7ee", "nome": "Análise documental inicial da empresa e do estabelecimento.", "ordem": 1, "prazo": ""}, {"id": "e96d88c2-4dba-479d-8386-85eec07d0471", "nome": "Conferência da compatibilidade entre atividade, estrutura física e dados cadastrais.", "ordem": 2, "prazo": ""}, {"id": "5f34b801-3aa6-41ca-806b-af80c2fd239d", "nome": "Organização dos dados do responsável técnico e da equipe vinculada.", "ordem": 3, "prazo": ""}, {"id": "cfc6135a-594d-4686-abe8-58565d498d2b", "nome": "Preenchimento técnico no SCNES.", "ordem": 4, "prazo": ""}, {"id": "638bea9c-006e-4c15-945c-093e43b24c28", "nome": "Geração do arquivo e protocolo junto ao órgão competente.", "ordem": 5, "prazo": ""}, {"id": "f52114d4-8e77-47d5-ac6c-e27546c49707", "nome": "Acompanhamento até a conclusão do cadastro e atendimento de eventuais exigências.", "ordem": 6, "prazo": ""}]', '[{"id": "183e83b1-dcfb-4ae6-839e-4ead66181606", "titulo": "Estruturação correta do estabe", "descricao": ""}, {"id": "cd41a464-0896-4853-8a98-f6b6c5378024", "titulo": "Organização cadastral", "descricao": ""}, {"id": "f781a852-1943-4470-8dc5-60ef79f1c6db", "titulo": "Segurança técnica", "descricao": ""}]', 'Regularização cadastral para estruturação do estabelecimento de saúde e apoio à operação com convênios e auditorias', NULL, NULL, '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('fb958a97-fc9f-4fbe-aebe-3bfe977ffa01', 19, 'NUCLEO TAO REABILITACAO E SAUDE LTDA', '63.838.968/0001-01', NULL, NULL, NULL, 'avulso', '[{"id": "74224bfd-a62f-471a-8edc-755072ea7bed", "ordem": 0, "prazo": "20 a 60 dias úteis", "secao": "geral", "detalhes": "<p>Análise técnica do CLI parcial, conferência da documentação já emitida, verificação das pendências da Vigilância Sanitária, identificação de eventuais exigências complementares, organização das respostas ao órgão competente, protocolo de complementação documental e acompanhamento do processo até a emissão ou renovação da licença sanitária.</p>", "taxa_max": 1500, "taxa_min": 0, "descricao": "Regularização e acompanhamento do licenciamento sanitário", "honorario": 2480, "isOptional": false, "quantidade": 1, "valor_mercado": 3800, "valor_premium": 5000, "docs_necessarios": "podendo variar conforme exigências do órgão", "honorario_contador": 0, "honorario_minimo_contador": 3000}, {"id": "dc5c3e47-bf0e-410d-98f3-79a5190217d4", "ordem": 2, "prazo": "8 a 15 a úteis", "secao": "geral", "detalhes": "<p><strong>Renovação do Auto de Vistoria do Corpo de Bombeiros (AVCB), </strong>com atuação técnica de engenheiro habilitado e emissão de ART, incluindo vistoria do imóvel, conferência das condições de segurança contra incêndio, preparação da documentação técnica, adequações necessárias e protocolo até a emissão ou renovação do certificado.<br><br><strong>Renovação do AVCB</strong> com engenheiro habilitado e emissão de ART, incluindo vistoria técnica, conferência de conformidade, organização documental e acompanhamento até a renovação do certificado.</p>", "taxa_max": 3000, "taxa_min": 800, "descricao": "Renovação do AVCB", "honorario": 2700, "isOptional": true, "quantidade": 1, "valor_mercado": 3500, "valor_premium": 5000, "docs_necessarios": "CNPJ, dados da empresa, AVCB anterior, planta/projeto, ART do responsável técnico, laudos técnicos e comprovação de manutenção dos sistemas de segurança, além de eventuais documentos adicionais conforme a edificação e a vistoria.", "honorario_contador": 0, "honorario_minimo_contador": 3000}]', '[]', '[]', 5180.00, 1, 0.00, 5180.00, false, 0.00, 0.00, 15, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p>A Vigilância Sanitária <strong>poderá exigir licenças</strong>, documentos técnicos, adequações estruturais ou comprovações adicionais antes da emissão final da licença sanitária. O presente orçamento contempla a atuação técnica para conferência, resposta às exigências e acompanhamento do processo, mas eventuais custos de terceiros, taxas públicas ou adequações físicas não estão incluídos, salvo se expressamente mencionados na proposta.<br><br>Trata-se de processo de <strong>média a alta complexidade regulatória</strong>, pois envolve licenciamento sanitário de clínica de saúde em funcionamento, com análise de documentação já emitida, possível necessidade de complementação técnica e atendimento a exigências específicas da Vigilância Sanitária, que poderá solicitar licenças, laudos, adequações ou retificações adicionais antes da conclusão da regularização.</p>', 'rascunho', '161fc5dda5413f059edb4bab0a706226', '8720a1a8-b08c-42b4-a539-228d6a8b6913', NULL, NULL, '2026-04-23 16:43:49.723684+00', '2026-04-23 16:43:49.723684+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>A empresa já possui o CLI parcial emitido pelo Portal Facilidade SP, com licenciamento integrado em andamento, porém a <strong>Vigilância Sanitária ainda não concluiu sua análise</strong> e o alvará atual vence em <strong>maio de 2026</strong>. O estabelecimento exerce atividade de fisioterapia e possui licenças integradas já deferidas em outros órgãos, mas permanece sujeito à análise da Vigilância Sanitária, que poderá exigir documentos complementares, ajustes técnicos ou licenças adicionais para viabilizar a emissão final da licença sanitária. O serviço proposto visa conduzir o processo de regularização, responder exigências, organizar a documentação e acompanhar a obtenção da licença até sua efetiva conclusão.</p>', NULL, '[{"id": "6ee75d9b-0708-4453-8a25-1274a0a5c168", "nome": "VISA + AVCB", "descricao": "Pacote de Regularização Sanitária (VISA) + Renovação do AVCB, com desconto de 8% aplicado sobre o valor total dos serviços. O pacote contempla a condução integral da licença sanitária junto à Vigilância Sanitária e da renovação do AVCB com acompanhamento técnico e documental, incluindo a atuação do engenheiro parceiro para o procedimento de bombeiros. Para o AVCB, o único custo adicional será a ART, que será emitida pelo profissional responsável.", "itens_ids": ["74224bfd-a62f-471a-8edc-755072ea7bed", "dc5c3e47-bf0e-410d-98f3-79a5190217d4"], "desconto_pct": 8}]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'cliente_via_contador', '[{"id": "b79572dd-366e-4c4a-8133-9c38dd0dd149", "condicao": "", "penalidade": "A Vigilância Sanitária pode exigir documentação adicional além da já apresentada."}, {"id": "9e557182-cf58-4d05-832d-a32a1c393295", "condicao": "", "penalidade": "Eventuais inconsistências entre o que foi licenciado e o que está em funcionamento podem gerar exigências."}, {"id": "a6983189-c262-49dc-a244-b4fe2c8fc51b", "condicao": "", "penalidade": "O vencimento do AVCB em maio de 2026 pode comprometer a continuidade da regularidade se não houver renovação a tempo."}, {"id": "651c1525-42fe-4bdc-8006-7e8fbc923e20", "condicao": "", "penalidade": "A ausência de atendimento às notificações pode gerar indeferimento, suspensão ou necessidade de novo protocolo."}, {"id": "fd1ef411-28e1-46ff-8b70-ec1f92ce7349", "condicao": "", "penalidade": "O órgão pode solicitar atualização de plantas, documentos técnicos ou comprovação de adequação estrutural."}]', '[{"id": "462f9053-f4f6-4f16-bb2e-ce16ba40f8fe", "nome": "Análise do CLI parcial já emitido.", "ordem": 1, "prazo": ""}, {"id": "6fad4290-d143-4bc4-a262-824a5a8063f6", "nome": "Verificação da situação atual do processo e do prazo de vencimento da licença.", "ordem": 2, "prazo": ""}, {"id": "9db5d008-d48d-48de-83e0-83cf0a2c47a7", "nome": "Conferência da documentação técnica e societária.", "ordem": 3, "prazo": ""}, {"id": "95fecc51-c64e-4dd8-9140-523a982058f6", "nome": "Identificação de eventuais pendências ou exigências da Vigilância Sanitária.", "ordem": 4, "prazo": ""}, {"id": "00a2d6d4-cc44-4aad-af6d-4071aaa46504", "nome": "Preparação e protocolo das respostas complementares.", "ordem": 5, "prazo": ""}, {"id": "29990728-3858-44b6-a96b-3f475a512267", "nome": "Acompanhamento até a liberação ou renovação da licença sanitária.", "ordem": 6, "prazo": ""}]', '[]', 'Regularização ou renovação da licença sanitária com acompanhamento técnico até a conclusão do processo', NULL, NULL, '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('9ceac507-be97-4f8d-829b-ca5fcdc489ee', 20, 'INSTITUTO SOCIAL KUZUALA', '20.966.772/0001-90', NULL, NULL, NULL, 'avulso', '[{"id": "fbac8b10-718c-4f92-a548-26a262ae9bf6", "ordem": 0, "prazo": "", "secao": "geral", "detalhes": "<p>Elaboração, consolidação e registro da ata correspondente ao período de 2016 a 2018, com reconstrução formal dos atos de gestão praticados no intervalo, acompanhada dos documentos acessórios exigidos para o protocolo cartorário, inclusive requerimento, edital de convocação, termo de posse e lista de presença.</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Ata 2016 a 2018", "honorario": 3500, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "33e4f2b6-a829-4206-bf31-1695c83d88ff", "ordem": 2, "prazo": "", "secao": "geral", "detalhes": "<p>Elaboração, consolidação e registro da ata correspondente ao período de 2018 a 2020, com formalização retroativa dos atos administrativos e institucionais praticados no período, observando a coerência com a linha histórica da entidade e a documentação complementar exigida pelo cartório.</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Ata 2018 a 2020", "honorario": 3500, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "0cee0645-a1af-46b2-bd71-f482e1735928", "ordem": 3, "prazo": "", "secao": "geral", "detalhes": "<p>Elaboração, consolidação e registro da ata correspondente ao período de 2020 a 2022, com reconstrução documental do respectivo ciclo de gestão, organização dos atos deliberativos e preparação de toda a documentação acessória necessária para análise e registro.</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Ata 2020 a 2022", "honorario": 3499, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "789806ce-9b70-433e-92f4-d12ea76f4d43", "ordem": 4, "prazo": "", "secao": "geral", "detalhes": "<p>Elaboração, consolidação e registro da ata correspondente ao período de 2022 a 2024, com formalização retroativa das deliberações e composição documental completa para fins de regularização da sequência histórica da entidade perante o cartório competente.</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Ata 2022 a 2024", "honorario": 3500, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "6e174cf6-b4fa-4e27-a219-67afc5a3da5c", "ordem": 5, "prazo": "", "secao": "geral", "detalhes": "<p>Elaboração e registro da ata correspondente ao período de 2024 a 2026, já contemplando a deliberação formal sobre a <strong>transformação do tipo jurídico da entidade em associação sem fins lucrativos</strong>, bem como a <strong>refatoração integral do estatuto social</strong>, com adequação das cláusulas institucionais, governança, finalidades, regras de administração e demais disposições necessárias ao novo enquadramento jurídico.</p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Ata 2024 a 2026 + transformação jurídica + estatuto social", "honorario": 4000, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 17999.00, 1, 7.00, 16739.07, false, 0.00, 0.00, 15, '<p>50% na assinatura e 50% na conclusão de cada etapa/entrega.</p>', NULL, '<p>Este orçamento contempla a regularização documental retroativa da entidade, com registro sequencial das atas e posterior transformação jurídica para associação sem fins lucrativos. Por se tratar de reconstrução histórica, cada etapa depende da conclusão e do deferimento da anterior, podendo haver ajustes técnicos de redação, forma e cronologia para adequação às exigências do cartório competente.</p><p><strong>Riscos</strong></p><ul><li><p><strong>Exigência cartorária adicional:</strong> o cartório pode solicitar ajustes, complementações ou readequação de texto.</p></li><li><p><strong>Inconsistência documental:</strong> divergência entre atas, estatuto, listas de presença e termos de posse.</p></li><li><p><strong>Maior rigor na análise:</strong> por serem atas retroativas, a conferência documental tende a ser mais criteriosa.</p></li><li><p><strong>Dependência entre etapas:</strong> cada registro somente poderá avançar após o deferimento do anterior.</p></li><li><p><strong>Custos cartorários variáveis:</strong> os emolumentos serão definidos após a prenotação, conforme a quantidade de páginas e a tabela do cartório.</p></li></ul><p><strong>Emolumentos cartorários</strong></p><p>Os valores cartorários serão apurados após a prenotação, pois cada cartório cobra de acordo com a quantidade de páginas e a natureza do ato. Para fins de estimativa, <strong>cada ata poderá variar entre R$ 800,00 e R$ 1.500,00</strong>, podendo haver acréscimo na etapa final de transformação jurídica e refatoração do estatuto social.</p>', 'rascunho', '298a0cf21ff244145dc4470dcbc2b3e1', '86fd9264-8ae5-418e-ba2b-7f2c726bfb75', NULL, NULL, '2026-04-24 18:40:52.925098+00', '2026-04-24 18:40:52.925098+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>A entidade possui registro original de fundação e eleição datada de 2014, porém, após contato com o cartório responsável, constatou-se que <strong>não existem registros posteriores formalizados</strong>. Diante disso, será necessário realizar um <strong>processo completo de regularização documental</strong>, com o registro retroativo de atas correspondentes aos períodos de 2016 a 2018, 2018 a 2020, 2020 a 2022, 2022 a 2024 e 2024 a 2026, culminando com a <strong>transformação do tipo jurídico para associação sem fins lucrativos</strong> e a <strong>refatoração integral do estatuto social</strong>. Trata-se de procedimento de alta complexidade, pois exige reconstrução histórica dos atos, alinhamento documental entre atas, estatuto, requerimentos, listas de presença, termos de posse e validação cartorária compatível com a continuidade institucional da entidade.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'contador', '[{"id": "830e527f-552a-4e10-989a-59a241fd8b19", "condicao": "", "penalidade": ""}]', '[{"id": "b65a0aa4-346d-4e82-a55d-d44eab6e2ee7", "nome": "Análise da documentação existente", "ordem": 1, "prazo": ""}, {"id": "5b9fee2c-5b59-4925-80ba-270ea16a526b", "nome": "Reconstituição da linha histórica", "ordem": 2, "prazo": ""}, {"id": "adb6f4ef-72ba-44f1-963a-fe3700638fd7", "nome": "Elaboração da Ata 2016 a 2018", "ordem": 3, "prazo": ""}, {"id": "3d49d269-0220-4c4d-a484-a079591fa468", "nome": "Registro da Ata 2016 a 2018 no cartório", "ordem": 4, "prazo": ""}, {"id": "5aa78789-5f8f-4b07-b0b0-3d97b18cad71", "nome": "Elaboração da Ata 2018 a 2020", "ordem": 5, "prazo": ""}, {"id": "35503c90-67d2-46af-a1ec-72b4e15db524", "nome": "Registro da Ata 2018 a 2020 no cartório", "ordem": 6, "prazo": ""}, {"id": "f031e34a-9d47-46c1-b194-97301eba17e1", "nome": "Elaboração da Ata 2020 a 2022", "ordem": 7, "prazo": ""}, {"id": "0ec57af9-a950-4512-b473-1ed22f2c2b04", "nome": "Registro da Ata 2020 a 2022 no cartório", "ordem": 8, "prazo": ""}, {"id": "9dcfde11-34b8-4fda-ab03-eed850c07c9d", "nome": "Elaboração da Ata 2022 a 2024", "ordem": 9, "prazo": ""}, {"id": "87ac2554-bcdb-4862-baf5-5e544e0e293c", "nome": "Registro da Ata 2022 a 2024 no cartório", "ordem": 10, "prazo": ""}, {"id": "9e9bc374-6139-4912-8784-bfc5eeaf347f", "nome": "Elaboração da Ata 2024 a 2026 com transformação jurídica", "ordem": 11, "prazo": ""}, {"id": "8ff6ec7e-9552-44c4-bf48-1b7fa8803011", "nome": "Refatoração e registro do estatuto social", "ordem": 12, "prazo": ""}]', '[]', 'Regularização societária completa com reconstrução documental, registro retroativo de atas e transformação jurídica para associação sem fins lucrativos', NULL, NULL, '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('85a7589e-f62f-449a-93b0-db334f715365', 5, 'Daniela Molina', NULL, NULL, '19 98253-3051', NULL, 'avulso', '[{"id": "1967a73e-2352-45cf-897a-654539f50814", "ordem": 0, "prazo": "", "secao": "obrigatorios", "detalhes": "O serviço compreende a assessoria completa para a regularização da constituição da associação e sua devida inscrição cadastral:Viabilidade Cadastral: \n\nConsulta prévia junto à Prefeitura de Boituva para verificação da sede e nome empresarial.\n\nRedação de Atas e Ajuste de Estatuto: Elaboração da ata de assembleia para alteração da nova diretoria e revisão das cláusulas do estatuto social conforme as novas necessidades da cliente.\n\nProcessamento de DBE (Documento Básico de Entrada): Preenchimento e protocolo junto à Receita Federal para obtenção/atualização do CNPJ.\n\nProtocolo em Cartório: Gestão do registro de todos os atos constitutivos no Cartório de Registro de Títulos e Documentos e Civil de Pessoas Jurídicas de Boituva.\n\nAcompanhamento Processual: Monitoramento de exigências e atualizações até a entrega do registro finalizado.\n\nNota importante: Licenças de funcionamento, alvarás de bombeiros ou quaisquer licenças operacionais não estão inclusas nesta proposta.", "taxa_max": 0, "taxa_min": 0, "descricao": "Registro Completo", "honorario": 2900, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 2900.00, 1, 0.00, 2900.00, false, 0.00, 0.00, 15, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p>Taxas de Terceiros: Não inclusas (custos de cartório e taxas municipais/estaduais serão repassados para pagamento pela cliente conforme as guias forem geradas).</p>', 'rascunho', '129a6856d67c4071775f6679e5b5da54', NULL, NULL, NULL, '2026-04-08 18:21:51.91564+00', '2026-04-08 18:21:51.91564+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>A associação terá atuação sobre a área do loteamento Jardim Bella Vida, localizado no Bairro Água Branca, em Boituva/SP, objeto da Matrícula nº 19.560. A finalidade é a prestação de serviços de conservação, segurança e manutenção da infraestrutura em prol dos associados.</p>', 'Para garantir a agilidade, seguiremos este fluxo:
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('f17e4ec5-8d6a-423b-bdd3-13bf052d3264', 8, 'GPU LTDA', NULL, NULL, NULL, NULL, 'avulso', '[{"id": "149114d4-53bb-4c6b-b084-df84af01b6ad", "ordem": 0, "prazo": "30 a 45 dias após recebimento dos documentos apostilados", "secao": "opcionais", "detalhes": "Descrição: Abertura de nova LTDA brasileira com GPU LTD (Bahamas) como sócia majoritária, incluindo CNPJ da estrangeira via Coleta Online.\nDetalhes/Escopo:\n\nViabilidade na Junta Comercial/Prefeitura via Redesim.\n\nRedação do Contrato Social com nomeação de administrador residente (pode ser Gabriel ou outro sócio em BH/MG).\n\nDBE e ativação de 2 CNPJs (estrangeira + brasileira).\n\nDocumentos necessários (GPU LTD): Certificate of Incorporation, Memorandum & Articles of Association, Certificate of Good Standing (todos apostilados nas Bahamas), Register of Members (comprovando sócios brasileiros), Procuração simples (facilitada por residência local).", "taxa_max": 3500, "taxa_min": 1800, "cenarioId": "701f73e4-9e22-4828-8644-5d798aadbd56", "descricao": "Constituição de Subsidiária Brasileira (GPU LTDA) + Inscrição de Sócio Estrangeiro (RECOMENDADO - 99% dos casos)", "honorario": 2000, "isOptional": false, "quantidade": 1, "valor_mercado": 5800, "valor_premium": 8000, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 4500}, {"id": "1a2a82af-3082-4ce3-9c15-61041a48dd43", "ordem": 2, "prazo": "90 a 180 dias", "secao": "opcionais", "detalhes": "Descrição: Autorização federal (DREI) para GPU LTD operar diretamente como filial no Brasil.\n\nDetalhes/Escopo:\n\nPedido administrativo com exame de estatuto estrangeiro.\n\nDepósito de capital destacado e publicação em Diário Oficial.\n\nDocumentos necessários (GPU LTD): Mesmos do Item 01 + Ata autorizando filial, Último balanço patrimonial apostilado, Comprovante de capital.\n\nCustos adicionais estimados: Mín: R$4.000 (mais balanço/traduções) / Máx: R$7.500 (publicações extras + DREI).", "taxa_max": 7500, "taxa_min": 4000, "cenarioId": "581d3003-ce16-4493-b70b-3cba4e9145d4", "descricao": "Nacionalização/Filial Direta da GPU LTD (OPCIONAL - Alta Complexidade)", "honorario": 10000, "isOptional": false, "quantidade": 1, "valor_mercado": 17800, "valor_premium": 2000, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 14000}]', '[]', '[]', 12000.00, 1, 0.00, 12000.00, false, 0.00, 0.00, 30, '<p>Pagamento via Pix ou Boleto Bancário, 50% no aceite da proposta e 50% na conclusão (entrega do CNPJ operacional ativo).</p>', NULL, '<p>Taxas terceiros NÃO inclusas: Apostila (~US$80-120 total), Tradução (~R$500-1.000), Cartório/Junta (~R$500-1.000). Riscos fiscais: 25% IR retenção em lucros para Bahamas; Declaração CBE anual (BC) para UBOs brasileiros. Sem mudanças RFB pós-2024 específicas para Bahamas (Portaria MF 2.029/2024 permite exclusão por investimento, mas não aplica automaticamente).</p>', 'enviado', 'f24b86fe7ef922511b9503b9edea2d55', 'cb1daf08-b59c-41a2-897e-f864f96d93f5', NULL, NULL, '2026-04-09 15:46:37.941065+00', '2026-04-09 15:46:37.941065+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>GPU LTD (International Business Company das Bahamas, sede em 201 Church St, Nassau, Good Standing 22/05/2023) precisa regularizar operações no Brasil. Seus sócios brasileiros (Gabriel, Marcelo, Catarina - residentes em Belo Horizonte/MG) facilitam o processo, permitindo que atuem como administradores locais sem procurador externo.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'cliente_via_contador', '[]', '[{"id": "8f0b67b0-8b5d-4c7f-87f2-c1f4f29c1c2f", "nome": "Apostilamento Haia nas Bahamas ", "ordem": 1, "prazo": "US$20/doc oficial - Ministry of Foreign Affairs Nassau)."}, {"id": "87cfbe71-bc16-432e-87fe-c170ae3d4d61", "nome": "Tradução juramentada no Brasil ", "ordem": 2, "prazo": "R$90-110/lauda + Registro em Cartório RTD."}, {"id": "48aa0b32-8516-41fb-a3fe-0b938e3a86b9", "nome": "Opção 1 Específica:", "ordem": 3, "prazo": "DBE/Coleta Online (CNPJ GPU LTD) + Registro Contrato Social na Junta Comercial via Redesim.  Entrega CNPJs ativos."}, {"id": "81a6790d-25c0-4d93-9c0c-e2fd2158d915", "nome": "Opção 2 Específica:", "ordem": 4, "prazo": "Protocolo no DREI + Aprovação federal + Arquivamento Junta.  Publicação DOU + CNPJ filial."}]', '[]', 'Habilitação de empresa extrangeira', NULL, NULL, '[{"id": "701f73e4-9e22-4828-8644-5d798aadbd56", "nome": "Opção A", "ordem": 1, "descricao": "Constituição de Subsidiária Brasileira"}, {"id": "581d3003-ce16-4493-b70b-3cba4e9145d4", "nome": "Opção B", "ordem": 2, "descricao": "Filial Direta da GPU LTD "}]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-05-09 15:46:37.941065+00', false);
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('710f210a-579f-456c-a5da-f8363d74556c', 4, 'CLINICA MATER SENIOR SAUDE E LONGEVIDADE LTDA', '65.843.530/0001-47', 'contato@alassessoriacontabil.com', '(11)94015-9661', NULL, 'avulso', '[{"id": "6e80fcb7-bb27-4944-b7a8-a6d26dab84d9", "ordem": 1, "prazo": "15 a 45 dias", "secao": "obrigatorios", "detalhes": "Licenciamento RPCI para clínicas médicas (H-6, 451m², 2 pavimentos, lotação 36). Avalia segurança contra incêndio/pânico. Protocolo ITJ-1240457 já classificado baixa complexidade.\n\nO que é/Pra que serve: Autorização CBMSC para operar com medidas preventivas (extintores, saídas, sinalização). Sem ela, nenhuma outra licença avança.", "taxa_max": 3100, "taxa_min": 1300, "descricao": "LICENÇA BOMBEIROS (CBMSC - RPCI Baixa Complexidade H-6)", "honorario": 3000, "isOptional": false, "quantidade": 1, "valor_mercado": 4800, "valor_premium": 7000, "docs_necessarios": "CNPJ, Contrato Social, planta/layout as-built, ART/RRT responsável técnico, questionário enquadramento (já preenchido)", "honorario_contador": 0, "honorario_minimo_contador": 4500}, {"id": "205d7428-a9e2-4b2f-9b14-bc8fa0fe965d", "ordem": 2, "prazo": "20 a 60 dias", "secao": "obrigatorios", "detalhes": "Alvará de funcionamento sanitário para clínicas ambulatoriais com múltiplas CNAEs (médica, nutrição, fisio, psico, estética). Exige salas segregadas, fluxos pacientes, biossegurança.\n\nO que é/Pra que serve: Autoriza operação conforme normas ANVISA/DIVESA-SC (esterilização, resíduos, fluxo contaminado/limpo). Pré-requisito para CRM/CNES. Sem ele = interdição imediata.", "taxa_max": 3300, "taxa_min": 2000, "descricao": "ALVARÁ SANITÁRIO – VIGILÂNCIA SANITÁRIA (DIVESA/PMF)", "honorario": 4500, "isOptional": false, "quantidade": 1, "valor_mercado": 5800, "valor_premium": 7000, "docs_necessarios": "Licença Bombeiros, planta baixa com layout/fluxos, declaração RT médico/enfermeiro, roteiro autoinspeção, comprovante endereço.", "honorario_contador": 0, "honorario_minimo_contador": 5000}, {"id": "4c7d656e-15cc-4c87-a5df-5e36c50ff516", "ordem": 3, "prazo": "5 a 15 dias", "secao": "obrigatorios", "detalhes": "Atualização processo 79278/2026 (já DEFERIDO) no Cadastro Técnico Municipal PMF. Sincroniza após licenças principais.\n\nO que é/Pra que serve: Registro oficial da prefeitura para fiscalização urbanística/ambiental. Mantém alvará funcionamento ativo.", "taxa_max": 500, "taxa_min": 200, "descricao": "ATUALIZAÇÃO CADASTRO TÉCNICO – PREFEITURA FLORIANÓPOLIS", "honorario": 600, "isOptional": false, "quantidade": 1, "valor_mercado": 800, "valor_premium": 1000, "docs_necessarios": "Licenças Bombeiros/Vigilância, CNPJ, Contrato Social, Alvará Funcionamento preliminar.", "honorario_contador": 0, "honorario_minimo_contador": 800}, {"id": "1dfa963a-0398-4964-8b3d-52a27faadcb4", "ordem": 4, "prazo": "1 a 15 dias ", "secao": "obrigatorios", "detalhes": "Autodeclaração SCBMS (já deferida) – sistema integrador JUCESC de licenças unificadas (Bombeiros, Vigilância, Prefeitura).\n\nO que é/Pra que serve: Centraliza/comunica todas licenças estaduais. Atualização final pós-principais.", "taxa_max": 100, "taxa_min": 60, "descricao": "ATUALIZAÇÃO SC BEM MAIS SIMPLES (JUCESC)", "honorario": 250, "isOptional": false, "quantidade": 1, "valor_mercado": 400, "valor_premium": 500, "docs_necessarios": "Licenças atualizadas 1-3, dados cadastrais JUCESC.", "honorario_contador": 0, "honorario_minimo_contador": 400}, {"id": "46cff7e8-b508-41fb-b26e-3aa6eb5151f9", "ordem": 5, "prazo": "15 a 30 dias ", "secao": "obrigatorios", "detalhes": " Inscrição Pessoa Jurídica para CNAE médico principal (86.30-5/03). Atualmente sem RT habilitado.\n\nO que é/Pra que serve: Habilita operação médica legal; fiscaliza ética/RT. Sem CRM = proibição atividade médica.", "taxa_max": 1400, "taxa_min": 1400, "descricao": "REGISTRO CRM PJ (CRM-SC)", "honorario": 4000, "isOptional": false, "quantidade": 1, "valor_mercado": 5500, "valor_premium": 8000, "docs_necessarios": " Formulário PJ, Termo Responsabilidade Técnica (médico CRM ativo), CNPJ/Contrato, Alvarás Vigilância/Prefeitura/Bombeiros, declaração capacitação técnica.", "honorario_contador": 0, "honorario_minimo_contador": 5000}, {"id": "6347dc02-881f-4d81-a38e-0b29be64ac97", "ordem": 6, "prazo": "20 a 40 dias ", "secao": "opcionais", "detalhes": "Cadastro Nacional Estabelecimentos Saúde via SMS-PMF. Atualmente \"sem dados\".\n\nO que é/Pra que serve: Lista oficial SUS/convênios; essencial para reembolso, planejamento, auditoria. Bloqueia receita sem ele.", "taxa_max": 500, "taxa_min": 200, "descricao": "CADASTRO CNES (SMS FLORIANÓPOLIS) Altamente Recomendado", "honorario": 1500, "isOptional": false, "quantidade": 1, "valor_mercado": 2300, "valor_premium": 3000, "docs_necessarios": "Fichas CNES assinadas digitalmente, CNPJ/Contrato, todas licenças anteriores, RT saúde.", "honorario_contador": 0, "honorario_minimo_contador": 2000}, {"id": "15851be2-a646-4f93-b7d9-cd46ab7925e6", "ordem": 7, "prazo": "8 a 18 meses", "secao": "opcionais", "detalhes": "\"CLÍNICA MATER SENIOR\" (Classe 44 Saúde). Disponível, mas risco similares (\"Master Senior\").\n\nO que é/Pra que serve: Proteção vitalícia contra cópias; valoriza negócio (branding/venda futura). Não trava operação.", "taxa_max": 745, "taxa_min": 355, "descricao": "REGISTRO MARCA INPI", "honorario": 2800, "isOptional": false, "quantidade": 1, "valor_mercado": 4000, "valor_premium": 5000, "docs_necessarios": " Formulário INPI, dados empresa, logotipo (opcional mista).", "honorario_contador": 0, "honorario_minimo_contador": 3500}]', '[]', '[]', 16650.00, 1, 0.00, 16650.00, false, 0.00, 0.00, 15, 'Pagamento à vista via PIX/boleto bancário ou parcelamento em até 6x.', NULL, '<p><strong>Taxas governamentais, emuletos, responsabilidade técnica laudada não estão inclusas no valor</strong></p>', 'enviado', '7763c05bbab5616b6741e8b19ff938cf', 'c8cc682a-7e58-49eb-8e46-076fa2f6fe53', NULL, NULL, '2026-04-07 21:16:03.044956+00', '2026-04-07 21:16:03.044956+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', 'Este orçamento abrange a implantação completa de licenças e cadastros essenciais para regularizar a Clínica Mater Senior Saúde e Longevidade Ltda (CNPJ 65.843.530/0001-47), com 451m² em 2 pavimentos e atividades diversificadas (médica, nutrição, fisioterapia, psicologia, estética). Atualmente sem licenças chave (CRM PJ, Vigilância Sanitária, Bombeiros), a clínica enfrenta riscos de multas (R$5k-50k), interdição e bloqueio de convênios. Nosso escopo elimina esses riscos em 6-12 semanas, com honorários fixos por item (expertise full) + taxas externas estimadas (pagas diretamente aos órgãos). Flexibilidade: itens individuais, pacotes com desconto ou personalizado – transformando burocracia em operação 100% legal e estratégica.', 'Sequência otimizada evita dependências e retrabalho:
INSERT INTO public.orcamentos (id, numero, prospect_nome, prospect_cnpj, prospect_email, prospect_telefone, prospect_contato, tipo_contrato, servicos, naturezas, escopo, valor_base, qtd_processos, desconto_pct, valor_final, desconto_progressivo_ativo, desconto_progressivo_pct, desconto_progressivo_limite, validade_dias, pagamento, sla, observacoes, status, share_token, cliente_id, convertido_em, pdf_url, created_at, updated_at, created_by, prazo_execucao, empresa_id, contexto, ordem_execucao, pacotes, secoes, destinatario, riscos, etapas_fluxo, beneficios_capa, headline_cenario, enviado_em, aprovado_em, cenarios, senha_link, prazo_pagamento_dias, observacoes_recusa, recusado_em, itens_selecionados, cenario_selecionado, clicksign_document_key, contrato_assinado_url, pago_em, data_expiracao, is_archived) VALUES ('8fc5859a-41e0-4c00-93cf-ac30c9d06bac', 7, 'LUCAS ANDRE GUZZARDI', NULL, 'suplica.ltda@gmail.com', '11 958655402', NULL, 'avulso', '[{"id": "80351f7e-f5be-466e-932b-402cbd17812a", "ordem": 1, "prazo": "4 dias úteis", "secao": "geral", "detalhes": "<ol><li><p><strong>Análise Tributária Estratégica</strong><br><strong>O que é/Pra que serve:</strong> Estudo CNAE x faturamento x localização SP para regime ideal (Simples Nacional até R$4,8M, Lucro Real/Produtivo). Planejamento IBS/CBS 2026.<br><strong>Detalhes:</strong> Enquadramento otimizado + simulações alíquotas ISS 2-5% SP.<br><strong>Prazo:</strong> 3-5 dias | <strong>Tipo:</strong> Obrigatório | <strong>Prioridade:</strong> 1<br></p></li><li><p><strong>Constituição Sociedade Limitada (JUCESP/REDESIM)</strong><br><strong>O que é/Pra que serve:</strong> Elaboração Contrato Social + registro JUCESP + NIRE automático. Base legal da empresa.<br><strong>Detalhes:</strong> Sociedade ME/EPP com cláusulas pós-reforma + capital social mínimo.<br><strong>Prazo:</strong> 5-15 dias | <strong>Tipo:</strong> Obrigatório | <strong>Prioridade:</strong> 2<br></p></li><li><p><strong>Registro Órgãos Competentes (Receita Federal)</strong><br><strong>O que é/Pra que serve:</strong> Obtenção CNPJ + inscrição estadual SEFAZ-SP. Habilita movimentação bancária.<br><strong>Detalhes:</strong> Automático via REDESIM pós-JUCESP.<br><strong>Prazo:</strong> 1-5 dias | <strong>Tipo:</strong> Obrigatório | <strong>Prioridade:</strong> 3<br></p></li><li><p><strong>Habilitação Inscrição Municipal + NF3e (Prefeitura SP)</strong><br><strong>O que é/Pra que serve:</strong> CCM São Paulo + credenciamento NF3e/Sefip para serviços. Essencial para faturamento.<br><strong>Detalhes:</strong> Configuração portal SP + testes emissão + DAMSP.<br><strong>Prazo:</strong> 5-10 dias | <strong>Tipo:</strong> Obrigatório | <strong>Prioridade:</strong> 4<br></p></li><li><p><strong>Consultoria Pós-Reforma Tributária (IBS/CBS)</strong><br><strong>O que é/Pra que serve:</strong> Ajustes para dupla tributação 2026-2027 + planejamento diferencial ISS x CBS.<br><strong>Detalhes:</strong> Simulações CBS(serviços) x IBS(geral) + estratégia transição SP.<br><strong>Prazo:</strong> 10-20 dias (paralelo) | <strong>Tipo:</strong> Altamente Recomendado | <strong>Prioridade:</strong> 5</p></li></ol><p></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "Serviço Único Detalhado – Etapas Integradas (Ordem Otimizada)", "honorario": 2800, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 2800.00, 1, 0.00, 2800.00, false, 0.00, 0.00, 15, '<ul><li><p>Pagamento à vista via PIX com desconto</p></li><li><p>PARCELAMENTO EM ATÉ 3X SEM JUROS NO CARTÃO</p></li></ul><p></p>', NULL, '<p>Taxas pagas <strong>diretamente aos órgãos</strong> (JUCESP, Receita, PMF SP). Comprovante exigido para liberação etapas.</p>', 'rascunho', 'b6c0550bc44cc4eca56c4a7a465d897a', NULL, NULL, NULL, '2026-04-09 12:16:24.991567+00', '2026-04-09 12:16:24.991567+00', NULL, 'Prazo de execução: até 15 dias úteis após recebimento da documentação completa.', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>Este orçamento apresenta <strong>assessoria empresarial 360° em único serviço</strong> para <strong>constituição de Sociedade Empresária Limitada + análise tributária estratégica + registro nos órgãos competentes + habilitação de Inscrição Municipal (São Paulo/SP) para emissão de notas fiscais de prestação de serviços + consultoria e cuidados pós-Reforma Tributária (2026)</strong>.<br></p><p>Serviço <strong>full service</strong> para novos negócios em <strong>São Paulo/SP</strong>, garantindo operação legal desde o zero: otimização fiscal (Simples Nacional/Real/Produtivo), conformidade Receita Federal/JUCESP/Prefeitura SP, emissão NF3e/Sefip e blindagem para transição IBS/CBS (Lei Complementar 214/2025). Elimina autuações, acelera <strong>15 dias úteis totais</strong>.</p>', NULL, '[{"id": "481e74b2-72de-4674-8f4e-c0509be12d0e", "nome": "PAGAMENTO VIA PIX", "descricao": "", "itens_ids": ["80351f7e-f5be-466e-932b-402cbd17812a"], "desconto_pct": 5}]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'cliente_direto', '[]', '[]', '[]', 'Introdução ao Escopo de Assessoria Empresarial Completa', NULL, NULL, '[]', NULL, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false);
