0, "descricao": "ESPACO NEGOCIOS & HOLDING GERAIS LTDA", "honorario": 30, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "d4933a77-2d7a-4097-ae17-288b2fad167a", "ordem": 4, "prazo": "", "secao": "geral", "detalhes": "<p><strong>Alterar Endereço Eletronico do CNPJ </strong></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "TC EXPRESSO ADMINISTRACAO E NEGOCIOS LTDA", "honorario": 30, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "91314cf3-c8ec-49eb-a266-2528e98e8262", "ordem": 5, "prazo": "", "secao": "geral", "detalhes": "<p><strong>Alterar Endereço Eletronico do CNPJ </strong></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "RKL PARTICIPACOES LTDA", "honorario": 30, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "2161b014-4501-41e7-a508-577531499f40", "ordem": 6, "prazo": "", "secao": "geral", "detalhes": "<p><strong>Alterar Endereço Eletronico e Telefone do CNPJ </strong></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "G-40 EMPREENDIMENTOS E PARTICIPACOES LTDA", "honorario": 35, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "bb9be587-2786-478a-97c5-ff11961b9d01", "ordem": 7, "prazo": "", "secao": "geral", "detalhes": "<p><strong>Alterar Endereço Eletronico do CNPJ </strong></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "CSP INVEST PARTICIPACOES LTDA", "honorario": 30, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}, {"id": "6c521ff5-aca1-4b6d-a1e8-199d0afd516c", "ordem": 8, "prazo": "", "secao": "geral", "detalhes": "<p><u>Cortésia no fio do bigode 👨🏻‍🦰</u><br><br><strong>ALTERAR TELEFONE E E-MAIL NO CNPJ</strong></p>", "taxa_max": 0, "taxa_min": 0, "descricao": "CSP PARTICIPAÇÕES LTDA", "honorario": 0, "isOptional": false, "quantidade": 1, "valor_mercado": 0, "valor_premium": 0, "docs_necessarios": "", "honorario_contador": 0, "honorario_minimo_contador": 0}]', '[]', '[]', 220.00, 1, 0.00, 220.00, false, 0.00, 0.00, 5, 'Pagamento à vista via PIX ou boleto bancário.', NULL, '<p>Caso possua procuração para todos os CNPJ''s, com o certificado eCPF ou eCNPJ da contabilidade, é possível realizar a transmissão do DBE.</p>', 'enviado', 'c728fddeffe7af855c6500a6aa00d056', '57e2ba95-1347-4535-8d81-155c2e4302eb', NULL, NULL, '2026-04-10 14:43:03.906596+00', '2026-04-10 14:43:03.906596+00', NULL, '1 dia útil', '2fa6a9bc-86f9-4831-9e76-c1fcd03f966d', '<p>A <strong>Fato Assessoria Contábil </strong>necessita atualizar os dados cadastrais de 7 empresas de sua carteira junto à Receita Federal. As alterações envolvem correção de e-mail e/ou telefone do quadro societário, por meio de DBE (Documento Básico de Entrada). Serviço padronizado, sem alteração contratual — apenas atualização de dados cadastrais via portal da Redesim/Receita Federal.</p>', NULL, '[]', '[{"key": "geral", "label": "Geral", "descricao": ""}, {"key": "obrigatorios", "label": "Itens Obrigatórios", "descricao": "Serviços necessários para regularização"}, {"key": "opcionais", "label": "Itens Opcionais", "descricao": "Serviços complementares recomendados"}]', 'contador', '[]', '[{"id": "33581d7d-3399-4f0a-9c3e-2fdb56fb6995", "nome": "Recepcionamento da documentação", "ordem": 1, "prazo": "CNPJ + CPF do sócio responsável"}, {"id": "94aa6792-5fc7-4f75-b1d9-2bdef87659db", "nome": "Elaboração e peticionamento do DBE", "ordem": 2, "prazo": "--"}, {"id": "0ed15ed8-2e40-4ace-8efe-7dd011ae02a8", "nome": "Salvar procolo e encaminhar para o Sr. Adenilson", "ordem": 3, "prazo": ""}, {"id": "975da13